// Quick test script to verify the classification API is working
// Run with: node test-classify.js

const testImage = 'data:image/jpeg;base64,';

fetch('http://localhost:3001/api/classify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ image: testImage })
})
.then(res => res.json())
.then(data => {
    console.log('✅ Classification API is working!');
    console.log('Response:', JSON.stringify(data, null, 2));
})
.catch(err => {
    console.error('❌ Classification API failed:');
    console.error(err.message);
    console.log('\nTroubleshooting:');
    console.log('1. Check if backend is running on http://localhost:3001');
    console.log('2. Verify GEMINI_API_KEY is set in backend/.env');
    console.log('3. Run: curl http://localhost:3001/api/health');
});
